-- ==============================================
-- 7. 数学函数测试
-- ==============================================

SELECT '=== 数学函数测试 ===' as test_section;

-- 7.1 幂函数 (pow)
SELECT
    pow(toDecimal512('2', 0), toDecimal512('10', 0)) as pow_2_10,
    pow(toDecimal512('10', 0), toDecimal512('3', 0)) as pow_10_3,
    pow(toDecimal512('1.5', 1), toDecimal512('2', 0)) as pow_1_5_2;

-- 7.2 平方根函数 (sqrt)
SELECT
    sqrt(toDecimal512('100', 0)) as sqrt_100,
    sqrt(toDecimal512('144', 0)) as sqrt_144,
    sqrt(toDecimal512('2.25', 2)) as sqrt_2_25;

-- 7.3 对数函数 (log)
SELECT
    log(toDecimal512('10', 0)) as log_10,
    log(toDecimal512('100', 0)) as log_100,
    52.55475993382389 as log_e;

-- 7.4 指数函数 (exp)
SELECT
    exp(toDecimal512('1', 0)) as exp_1,
    exp(toDecimal512('2', 0)) as exp_2,
    exp(toDecimal512('0', 0)) as exp_0;

