SELECT '===运算符优先级===';
SELECT toDecimal512('10', 0) + toDecimal512('2', 0) * toDecimal512('5', 0);
SELECT toDecimal512('10', 0) + toDecimal512('20', 0) / toDecimal512('5', 0);
SELECT toDecimal512('10', 0) + toDecimal512('2', 0) % toDecimal512('5', 0);
SELECT toDecimal512(10, 0) * toDecimal512(2, 0) % toDecimal512(5, 0);
SELECT toDecimal512(10, 0) / toDecimal512(2, 0) % toDecimal512(5, 0);
SELECT toDecimal512(2, 0) % toDecimal512(5, 0) * toDecimal512(10, 0);
SELECT toDecimal512(2, 0) % toDecimal512(5, 0) / toDecimal512(2, 0);
SELECT toDecimal512(10, 0) * -toDecimal512(2, 0) % toDecimal512(3, 0);
SELECT toDecimal512(10, 0) / -toDecimal512(2, 0) % toDecimal512(3, 0);
-- 优先级一元负号运算符 > 乘除取模 > 加减

-- 与各种运算函数优先级
SELECT toDecimal512(5, 0) * positiveModulo(toDecimal512(2, 0), toDecimal512(5, 0));
-- 函数 > 运算符

